package com.cardiofit.flink.models;

import com.fasterxml.jackson.annotation.JsonProperty;
import java.io.Serializable;
import java.time.Instant;
import java.util.HashMap;
import java.util.Map;
import java.util.Set;

/**
 * Routed event model representing events prepared for egress to various downstream systems
 * Generated by Module 6: Egress & Multi-Sink Routing
 */
public class RoutedEvent implements Serializable {
    private static final long serialVersionUID = 1L;

    @JsonProperty("id")
    private String id;

    @JsonProperty("source_event_id")
    private String sourceEventId;

    @JsonProperty("source_event_type")
    private String sourceEventType;

    @JsonProperty("patient_id")
    private String patientId;

    @JsonProperty("encounter_id")
    private String encounterId;

    @JsonProperty("routing_time")
    private long routingTime;

    @JsonProperty("priority")
    private Priority priority;

    @JsonProperty("destinations")
    private Set<String> destinations;

    @JsonProperty("transformation_rules")
    private Set<String> transformationRules;

    @JsonProperty("original_payload")
    private Object originalPayload;

    @JsonProperty("transformed_payloads")
    private Map<String, Object> transformedPayloads;

    @JsonProperty("routing_metadata")
    private RoutingMetadata routingMetadata;

    @JsonProperty("transformation_metadata")
    private Map<String, Object> transformationMetadata;

    @JsonProperty("delivery_requirements")
    private DeliveryRequirements deliveryRequirements;

    @JsonProperty("correlation_id")
    private String correlationId;

    @JsonProperty("routing_status")
    private RoutingStatus routingStatus;

    @JsonProperty("retry_count")
    private int retryCount;

    @JsonProperty("last_retry_time")
    private Long lastRetryTime;

    @JsonProperty("expiration_time")
    private Long expirationTime;

    // Default constructor
    public RoutedEvent() {
        this.routingTime = System.currentTimeMillis();
        this.priority = Priority.NORMAL;
        this.transformedPayloads = new HashMap<>();
        this.routingStatus = RoutingStatus.PENDING;
        this.retryCount = 0;
    }

    // Builder pattern
    public static Builder builder() {
        return new Builder();
    }

    public static class Builder {
        private RoutedEvent event = new RoutedEvent();

        public Builder id(String id) {
            event.id = id;
            return this;
        }

        public Builder sourceEventId(String sourceEventId) {
            event.sourceEventId = sourceEventId;
            return this;
        }

        public Builder sourceEventType(String sourceEventType) {
            event.sourceEventType = sourceEventType;
            return this;
        }

        public Builder patientId(String patientId) {
            event.patientId = patientId;
            return this;
        }

        public Builder encounterId(String encounterId) {
            event.encounterId = encounterId;
            return this;
        }

        public Builder routingTime(long routingTime) {
            event.routingTime = routingTime;
            return this;
        }

        public Builder priority(Priority priority) {
            event.priority = priority;
            return this;
        }

        public Builder destinations(Set<String> destinations) {
            event.destinations = destinations;
            return this;
        }

        public Builder transformationRules(Set<String> transformationRules) {
            event.transformationRules = transformationRules;
            return this;
        }

        public Builder originalPayload(Object originalPayload) {
            event.originalPayload = originalPayload;
            return this;
        }

        public Builder correlationId(String correlationId) {
            event.correlationId = correlationId;
            return this;
        }

        public RoutedEvent build() {
            return event;
        }
    }

    // Getters and Setters
    public String getId() { return id; }
    public void setId(String id) { this.id = id; }

    public String getSourceEventId() { return sourceEventId; }
    public void setSourceEventId(String sourceEventId) { this.sourceEventId = sourceEventId; }

    public String getSourceEventType() { return sourceEventType; }
    public void setSourceEventType(String sourceEventType) { this.sourceEventType = sourceEventType; }

    public String getPatientId() { return patientId; }
    public void setPatientId(String patientId) { this.patientId = patientId; }

    public String getEncounterId() { return encounterId; }
    public void setEncounterId(String encounterId) { this.encounterId = encounterId; }

    public long getRoutingTime() { return routingTime; }
    public void setRoutingTime(long routingTime) { this.routingTime = routingTime; }

    public Priority getPriority() { return priority; }
    public void setPriority(Priority priority) { this.priority = priority; }

    public Set<String> getDestinations() { return destinations; }
    public void setDestinations(Set<String> destinations) { this.destinations = destinations; }

    public Set<String> getTransformationRules() { return transformationRules; }
    public void setTransformationRules(Set<String> transformationRules) { this.transformationRules = transformationRules; }

    public Object getOriginalPayload() { return originalPayload; }
    public void setOriginalPayload(Object originalPayload) { this.originalPayload = originalPayload; }

    public Map<String, Object> getTransformedPayloads() { return transformedPayloads; }
    public void setTransformedPayloads(Map<String, Object> transformedPayloads) { this.transformedPayloads = transformedPayloads; }

    public RoutingMetadata getRoutingMetadata() { return routingMetadata; }
    public void setRoutingMetadata(RoutingMetadata routingMetadata) { this.routingMetadata = routingMetadata; }

    public Map<String, Object> getTransformationMetadata() { return transformationMetadata; }
    public void setTransformationMetadata(Map<String, Object> transformationMetadata) { this.transformationMetadata = transformationMetadata; }

    public DeliveryRequirements getDeliveryRequirements() { return deliveryRequirements; }
    public void setDeliveryRequirements(DeliveryRequirements deliveryRequirements) { this.deliveryRequirements = deliveryRequirements; }

    public String getCorrelationId() { return correlationId; }
    public void setCorrelationId(String correlationId) { this.correlationId = correlationId; }

    public RoutingStatus getRoutingStatus() { return routingStatus; }
    public void setRoutingStatus(RoutingStatus routingStatus) { this.routingStatus = routingStatus; }

    public int getRetryCount() { return retryCount; }
    public void setRetryCount(int retryCount) { this.retryCount = retryCount; }

    public Long getLastRetryTime() { return lastRetryTime; }
    public void setLastRetryTime(Long lastRetryTime) { this.lastRetryTime = lastRetryTime; }

    public Long getExpirationTime() { return expirationTime; }
    public void setExpirationTime(Long expirationTime) { this.expirationTime = expirationTime; }

    // Utility methods
    /**
     * Check if event has a specific destination
     */
    public boolean hasDestination(String destination) {
        return destinations != null && destinations.contains(destination);
    }

    /**
     * Add a destination to the routing list
     */
    public void addDestination(String destination) {
        if (destinations == null) {
            destinations = new java.util.HashSet<>();
        }
        destinations.add(destination);
    }

    /**
     * Remove a destination from the routing list
     */
    public void removeDestination(String destination) {
        if (destinations != null) {
            destinations.remove(destination);
        }
    }

    /**
     * Check if event has a specific transformation rule
     */
    public boolean hasTransformationRule(String rule) {
        return transformationRules != null && transformationRules.contains(rule);
    }

    /**
     * Add a transformation rule
     */
    public void addTransformationRule(String rule) {
        if (transformationRules == null) {
            transformationRules = new java.util.HashSet<>();
        }
        transformationRules.add(rule);
    }

    /**
     * Get transformed payload for a specific format
     */
    public Object getTransformedPayload(String format) {
        return transformedPayloads != null ? transformedPayloads.get(format) : null;
    }

    /**
     * Add a transformed payload
     */
    public void addTransformedPayload(String format, Object payload) {
        if (transformedPayloads == null) {
            transformedPayloads = new HashMap<>();
        }
        transformedPayloads.put(format, payload);
    }

    /**
     * Check if event is high priority
     */
    public boolean isHighPriority() {
        return priority == Priority.CRITICAL || priority == Priority.HIGH;
    }

    /**
     * Check if event requires immediate delivery
     */
    public boolean requiresImmediateDelivery() {
        return priority == Priority.CRITICAL ||
               (deliveryRequirements != null && deliveryRequirements.isRealTime());
    }

    /**
     * Check if event has expired
     */
    public boolean isExpired() {
        return expirationTime != null && System.currentTimeMillis() > expirationTime;
    }

    /**
     * Check if event needs retry
     */
    public boolean needsRetry() {
        return routingStatus == RoutingStatus.FAILED &&
               retryCount < getMaxRetries() &&
               !isExpired();
    }

    /**
     * Increment retry count
     */
    public void incrementRetryCount() {
        this.retryCount++;
        this.lastRetryTime = System.currentTimeMillis();
    }

    /**
     * Get maximum retry attempts based on priority
     */
    public int getMaxRetries() {
        switch (priority) {
            case CRITICAL:
                return 5;
            case HIGH:
                return 3;
            case NORMAL:
                return 2;
            case LOW:
                return 1;
            default:
                return 1;
        }
    }

    /**
     * Get routing age in milliseconds
     */
    public long getRoutingAge() {
        return System.currentTimeMillis() - routingTime;
    }

    /**
     * Get routing age in hours
     */
    public double getRoutingAgeHours() {
        return getRoutingAge() / (1000.0 * 3600.0);
    }

    /**
     * Check if routing is stale (older than specified hours)
     */
    public boolean isStale(double maxAgeHours) {
        return getRoutingAgeHours() > maxAgeHours;
    }

    /**
     * Get number of destinations
     */
    public int getDestinationCount() {
        return destinations != null ? destinations.size() : 0;
    }

    /**
     * Get number of transformation rules
     */
    public int getTransformationRuleCount() {
        return transformationRules != null ? transformationRules.size() : 0;
    }

    /**
     * Get number of transformed payloads
     */
    public int getTransformedPayloadCount() {
        return transformedPayloads != null ? transformedPayloads.size() : 0;
    }

    @Override
    public String toString() {
        return "RoutedEvent{" +
            "id='" + id + '\'' +
            ", sourceEventId='" + sourceEventId + '\'' +
            ", sourceEventType='" + sourceEventType + '\'' +
            ", patientId='" + patientId + '\'' +
            ", routingTime=" + Instant.ofEpochMilli(routingTime) +
            ", priority=" + priority +
            ", destinations=" + getDestinationCount() +
            ", transformationRules=" + getTransformationRuleCount() +
            ", routingStatus=" + routingStatus +
            ", retryCount=" + retryCount +
            '}';
    }

    // Inner classes for structured data
    public static class RoutingMetadata implements Serializable {
        private String routingEngine;
        private String routingVersion;
        private double routingLatency;
        private String routingNode;
        private Map<String, String> routingTags;

        public RoutingMetadata() {}

        // Getters and setters
        public String getRoutingEngine() { return routingEngine; }
        public void setRoutingEngine(String routingEngine) { this.routingEngine = routingEngine; }

        public String getRoutingVersion() { return routingVersion; }
        public void setRoutingVersion(String routingVersion) { this.routingVersion = routingVersion; }

        public double getRoutingLatency() { return routingLatency; }
        public void setRoutingLatency(double routingLatency) { this.routingLatency = routingLatency; }

        public String getRoutingNode() { return routingNode; }
        public void setRoutingNode(String routingNode) { this.routingNode = routingNode; }

        public Map<String, String> getRoutingTags() { return routingTags; }
        public void setRoutingTags(Map<String, String> routingTags) { this.routingTags = routingTags; }
    }

    public static class DeliveryRequirements implements Serializable {
        private boolean realTime;
        private boolean guaranteed;
        private boolean ordered;
        private int maxDeliveryAttempts;
        private long timeoutMs;
        private String deliveryMode;
        private Map<String, String> customRequirements;

        public DeliveryRequirements() {
            this.realTime = false;
            this.guaranteed = false;
            this.ordered = false;
            this.maxDeliveryAttempts = 3;
            this.timeoutMs = 30000; // 30 seconds default
            this.deliveryMode = "BEST_EFFORT";
        }

        // Getters and setters
        public boolean isRealTime() { return realTime; }
        public void setRealTime(boolean realTime) { this.realTime = realTime; }

        public boolean isGuaranteed() { return guaranteed; }
        public void setGuaranteed(boolean guaranteed) { this.guaranteed = guaranteed; }

        public boolean isOrdered() { return ordered; }
        public void setOrdered(boolean ordered) { this.ordered = ordered; }

        public int getMaxDeliveryAttempts() { return maxDeliveryAttempts; }
        public void setMaxDeliveryAttempts(int maxDeliveryAttempts) { this.maxDeliveryAttempts = maxDeliveryAttempts; }

        public long getTimeoutMs() { return timeoutMs; }
        public void setTimeoutMs(long timeoutMs) { this.timeoutMs = timeoutMs; }

        public String getDeliveryMode() { return deliveryMode; }
        public void setDeliveryMode(String deliveryMode) { this.deliveryMode = deliveryMode; }

        public Map<String, String> getCustomRequirements() { return customRequirements; }
        public void setCustomRequirements(Map<String, String> customRequirements) { this.customRequirements = customRequirements; }
    }

    // Enums for common values
    public enum Priority {
        LOW(4, "Low priority - batch processing acceptable"),
        NORMAL(3, "Normal priority - standard processing"),
        HIGH(2, "High priority - expedited processing"),
        CRITICAL(1, "Critical priority - immediate processing required");

        private final int level;
        private final String description;

        Priority(int level, String description) {
            this.level = level;
            this.description = description;
        }

        public int getLevel() {
            return level;
        }

        public String getDescription() {
            return description;
        }

        public boolean isHigherThan(Priority other) {
            return this.level < other.level; // Lower number = higher priority
        }
    }

    public enum RoutingStatus {
        PENDING("Routing pending"),
        IN_PROGRESS("Routing in progress"),
        COMPLETED("Routing completed successfully"),
        PARTIAL_SUCCESS("Partial routing success"),
        FAILED("Routing failed"),
        RETRY("Routing retry in progress"),
        EXPIRED("Routing expired"),
        CANCELLED("Routing cancelled");

        private final String description;

        RoutingStatus(String description) {
            this.description = description;
        }

        public String getDescription() {
            return description;
        }

        public boolean isFinal() {
            return this == COMPLETED || this == FAILED || this == EXPIRED || this == CANCELLED;
        }

        public boolean isSuccess() {
            return this == COMPLETED || this == PARTIAL_SUCCESS;
        }
    }

    public enum TransformationRule {
        FHIR_R4_TRANSFORM("Transform to FHIR R4 format"),
        HL7_V2_TRANSFORM("Transform to HL7 v2 format"),
        ANALYTICS_FLATTEN("Flatten for analytics processing"),
        CLINICAL_SUMMARY("Create clinical summary"),
        AUDIT_FORMAT("Format for audit trail"),
        PRIVACY_FILTER("Apply privacy filtering"),
        INTEROP_FORMAT("Format for interoperability"),
        REAL_TIME_FORMAT("Format for real-time consumption"),
        BATCH_FORMAT("Format for batch processing"),
        NOTIFICATION_FORMAT("Format for notifications");

        private final String description;

        TransformationRule(String description) {
            this.description = description;
        }

        public String getDescription() {
            return description;
        }
    }

    public enum Destination {
        CLINICAL_WORKFLOW("Clinical workflow systems"),
        CRITICAL_ALERTS("Critical alert management"),
        ANALYTICS("Analytics and reporting systems"),
        EXTERNAL_SYSTEMS("External integration systems"),
        AUDIT("Audit and compliance systems"),
        NOTIFICATION("Notification services"),
        PHARMACY_SYSTEMS("Pharmacy management systems"),
        LAB_SYSTEMS("Laboratory information systems"),
        QUALITY_SYSTEMS("Quality management systems"),
        CARE_COORDINATION("Care coordination platforms"),
        SAFETY_SYSTEMS("Patient safety systems"),
        RESEARCH_SYSTEMS("Research and clinical trial systems");

        private final String description;

        Destination(String description) {
            this.description = description;
        }

        public String getDescription() {
            return description;
        }
    }
}